const express = require('express');
const bodyParser = require('body-parser');
const session = require('express-session'); // Required for session management, assuming it's already set up

const app = express();
const PORT = 3000;

// --- Mock Database and Authentication Logic ---
// In a real application, this would interact with a database
// and use a secure password hashing library like bcrypt.
const usersDB = {
  'user123': {
    id: 'user123',
    username: 'testuser',
    passwordHash: 'password123' // For demonstration: plain text. USE HASHES IN PRODUCTION!
  }
};

// Mock function to simulate password comparison
const verifyPassword = async (providedPassword, storedPasswordHash) => {
  // In a real app, use bcrypt.compare(providedPassword, storedPasswordHash);
  return providedPassword === storedPasswordHash;
};
// --- End Mock ---

// Middleware to parse JSON request bodies
app.use(bodyParser.json());

// Session middleware setup (assuming this is already configured in your app)
// For demonstration purposes, a simple in-memory session store is used.
// In production, use a persistent store like connect-mongo or connect-redis.
app.use(session({
  secret: 'supersecretkey', // Use a strong, unique secret in production
  resave: false,
  saveUninitialized: false,
  cookie: { secure: false, maxAge: 24 * 60 * 60 * 1000 } // Set secure: true in production for HTTPS
}));

// Middleware to simulate authentication (e.g., checking if a user is logged in)
// In a real app, this middleware would be part of your existing authentication flow.
const isAuthenticated = (req, res, next) => {
  if (req.session && req.session.userId) {
    next();
  } else {
    res.status(401).json({ message: 'Unauthorized: Please log in.' });
  }
};

// Account Deletion Endpoint
app.post('/delete-account', isAuthenticated, async (req, res) => {
  const { password } = req.body;
  const userId = req.session.userId; // Get user ID from the session

  if (!password) {
    return res.status(400).json({ message: 'Password is required to delete your account.' });
  }

  // Retrieve user data from the "database"
  const user = usersDB[userId];

  if (!user) {
    // This case should ideally not happen if isAuthenticated ensures user existence
    // but it's good practice to check.
    return res.status(404).json({ message: 'User not found.' });
  }

  try {
    const isPasswordValid = await verifyPassword(password, user.passwordHash);

    if (isPasswordValid) {
      // Simulate account deletion
      delete usersDB[userId];
      console.log(`Account for user ${userId} has been deleted.`);

      // Destroy the user's session to log them out
      req.session.destroy(err => {
        if (err) {
          console.error('Error destroying session:', err);
          return res.status(500).json({ message: 'Account deleted, but failed to log out properly.' });
        }
        res.status(200).json({ message: 'Your account has been successfully deleted.' });
      });

    } else {
      res.status(401).json({ message: 'Incorrect password. Account deletion failed.' });
    }
  } catch (error) {
    console.error('Error during account deletion:', error);
    res.status(500).json({ message: 'An internal server error occurred during account deletion.' });
  }
});

